  // A "device-side" queue continues to exist while detached; the notifier doesn't.
  tb_q64_clear(&rt->notify_q);
  return TB_OK;
}

tb_status tb_link_attach(tb_rt *rt, uint32_t tick) {
  (void)tick;
  if (!rt)
    return TB_ERR_BAD_ARG;
  if (rt->attached)
    return TB_OK;

